  const config: LicenseConfig = {
    allowList: ["MIT"],
    denyList: ["GPL-3.0"],
  };

  test("output contains expected summary fields", async () => {
    const deps = [
      { name: "react", version: "^18.0.0" },
      { name: "gpl-package", version: "^1.0.0" },
